            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 3693249147883790810U;
            aOrbiterF = (aOrbiterF ^ aOrbiterI) ^ 18365859989736602556U;
            aOrbiterF = RotL64((aOrbiterF * 3348463719324104997U), 47U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterC) + 10645056678337549771U) + aOrbiterUpdateSaltC[((aIndex + 24U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 1175668356822251045U;
            aOrbiterE = RotL64((aOrbiterE * 6579675292775345579U), 19U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 13556844570541823717U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterF) ^ 4790355739411849736U) ^ aNonceWordF;
            aOrbiterA = RotL64((aOrbiterA * 4083544011788850307U), 23U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterI) + 14905575502272644116U;
            aOrbiterC = ((aOrbiterC ^ aOrbiterB) ^ 17047244574558476634U) ^ aOrbiterUpdateSaltA[((aIndex + 8U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 2356386971503880047U), 51U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterA) + 10161614295718414869U) + aOrbiterUpdateSaltD[((aIndex + 15U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterJ) ^ 13413914082651612468U;
            aOrbiterI = RotL64((aOrbiterI * 16224039093981079491U), 11U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterJ) + 6072693130156927774U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterE) ^ 4333656233793103787U) ^ aNonceWordH;
            aOrbiterB = RotL64((aOrbiterB * 9374745547133955709U), 43U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterD) + 17209776289202130250U;
            aOrbiterK = (aOrbiterK ^ aOrbiterA) ^ 11752001118070361543U;
            aOrbiterK = RotL64((aOrbiterK * 4416523594812872339U), 27U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterE) + 15367365111105608277U;
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 8650687767097460704U;
            aOrbiterD = RotL64((aOrbiterD * 11430451559660578667U), 37U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterF) + 18074648514448405693U) + aNonceWordJ;
            aOrbiterJ = (((aOrbiterJ ^ aOrbiterC) ^ 10857586858462237581U) ^ aOrbiterUpdateSaltF[((aIndex + 28U)) & S_SALT1]) ^ aNonceWordL;
            aOrbiterJ = RotL64((aOrbiterJ * 3722891011080095849U), 3U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterH) + 17219932344278345591U;
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 6318740973868639425U;
            aOrbiterG = RotL64((aOrbiterG * 8846295038878812229U), 5U);
            //
            aIngress = RotL64(aOrbiterB, 12U) ^ aOrbiterH;
            aIngress = aIngress + (RotL64(aOrbiterG, 51U) ^ aOrbiterD);
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterC, 19U));
            aIngress = aIngress + (RotL64(aOrbiterK, 21U) ^ aOrbiterJ);
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterA, 57U));
            aIngress = aIngress + RotL64(aOrbiterE, 23U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererH = aWandererH + ((RotL64(aCross, 58U) + RotL64(aOrbiterG, 24U)) + aOrbiterF);
            aWandererG = aWandererG ^ ((((RotL64(aIngress, 23U) + aOrbiterK) + RotL64(aOrbiterI, 43U)) + aNonceWordK) + aWandererUpdateSaltD[(((31U - aIndex) + 17U)) & S_SALT1]);
            aWandererF = aWandererF + (((RotL64(aPrevious, 19U) + aOrbiterH) + RotL64(aOrbiterC, 51U)) + RotL64(aCarry, 51U));
            aWandererA = aWandererA ^ ((RotL64(aScatter, 35U) + RotL64(aOrbiterG, 29U)) + aOrbiterE);
